request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?normalizedId ?orgId WHERE {
  ?org tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:normalizedId ?normalizedId .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .
  ?definitions tai:belongsTo ?model .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo ;
               bbo:name ?participantName .
  FILTER(CONTAINS(LCASE(STR(?participantName)), LCASE("Bewreber")))

  BIND(?org as ?orgId)
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?created ?normalizedId WHERE {
  ?org tai:organizationId "2dafb1f0acb24b27ae8f0dc47d14fcaa" .
  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created ;
         tai:normalizedId ?normalizedId .

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?participant a bboExt:Participant ;
               tai:belongsTo ?choreo .

  OPTIONAL { ?participant bbo:name ?pname1 . }
  OPTIONAL { ?participant rdfs:label ?pname2 . }

  FILTER(
    EXISTS { ?participant bbo:name ?pname1 . FILTER(CONTAINS(LCASE(STR(?pname1)), LCASE("Bewreber"))) }
    || EXISTS { ?participant rdfs:label ?pname2 . FILTER(CONTAINS(LCASE(STR(?pname2)), LCASE("Bewreber"))) }
    || EXISTS { ?participant bbo:name ?pname1 . FILTER(CONTAINS(LCASE(STR(?pname1)), LCASE("bewerber"))) }
    || EXISTS { ?participant rdfs:label ?pname2 . FILTER(CONTAINS(LCASE(STR(?pname2)), LCASE("bewerber"))) }
  )
}
ORDER BY DESC(?created)
LIMIT 25
